#include "acl/acl.h"
#include "data_utils.h"
#include "kernel_operator.h"

#ifdef ASCENDC_CPU_DEBUG
#include "cpu_debug_launch.h"
#endif

constexpr uint32_t scenarioNum = SCENARIO_NUM;

// 场景1：BlockReduceMax，输入half类型[1, 256]，输出[1, 16]，每个datablock内求最大值
// 场景2：BlockReduceMin，输入half类型[4, 128]，输出[4, 8]，每个datablock内求最小值
// 场景3：BlockReduceSum，输入float类型[1, 128]，输出[1, 16]，每个datablock内求和


template<typename T>
class KernelReduce {
    static constexpr uint32_t SRC_TOTAL_LENGTH = scenarioNum == 1 ? 256 : scenarioNum == 2 ? 512 : 128;
    static constexpr uint32_t DST_TOTAL_LENGTH = scenarioNum == 2 ? 32 : 16;
public:
    __aicore__ inline KernelReduce() {}
    __aicore__ inline void Init(__gm__ uint8_t* src, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ T*)src);
        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);
        pipe->InitBuffer(inQueueSrc, 1, SRC_TOTAL_LENGTH * sizeof(T));
        pipe->InitBuffer(outQueueDst, 1, DST_TOTAL_LENGTH * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, SRC_TOTAL_LENGTH);
        inQueueSrc.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueueDst.AllocTensor<T>();
        T zero(0);
        AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
        int32_t mask = 256 / sizeof(T);
        if constexpr (scenarioNum == 1) {
            // 场景1：BlockReduceMax：对每个datablock内所有元素求最大值
            // 每个datablock处理32字节(16个half元素)，256个元素共16个datablock，迭代16/8=2次
            // repeat=2, mask=128(256/sizeof(half)), srcBlkStride=1, srcRepStride=8, dstRepStride=1
            AscendC::BlockReduceMax<T>(dstLocal, srcLocal, 2, mask, 1, 1, 8);
        } else if constexpr (scenarioNum == 2) {
            // 场景2：BlockReduceMin：对每个datablock内所有元素求最小值
            // 每个datablock处理32字节(16个half元素)，512个元素共32个datablock，迭代32/8=4次
            // repeat=4, mask=128(256/sizeof(half)), srcBlkStride=1, srcRepStride=8, dstRepStride=1
            AscendC::BlockReduceMin<T>(dstLocal, srcLocal, 4, mask, 1, 1, 8);
        } else if constexpr (scenarioNum == 3) {
            // 场景3：BlockReduceSum：对每个datablock内所有元素求和
            // 每个datablock处理32字节(8个float元素)，128个元素共16个datablock，迭代16/8=2次
            // repeat=2, mask=64(256/sizeof(float)), srcBlkStride=1, srcRepStride=8, dstRepStride=1
            AscendC::BlockReduceSum<T>(dstLocal, srcLocal, 2, mask, 1, 1, 8);
        }

        outQueueDst.EnQue<T>(dstLocal);
        inQueueSrc.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueueDst.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, DST_TOTAL_LENGTH);
        outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<T> srcGlobal, dstGlobal;
};

__global__ __vector__ void block_reduce_custom(GM_ADDR x, GM_ADDR y)
{
    AscendC::TPipe pipe;
    if constexpr (scenarioNum == 1 || scenarioNum == 2) {
        KernelReduce<half> op;
        op.Init(x, y, &pipe);
        op.Process();
    } else if constexpr (scenarioNum == 3) {
        KernelReduce<float> op;
        op.Init(x, y, &pipe);
        op.Process();
    }
}

int32_t main(int32_t argc, char* argv[])
{
    uint32_t numBlocks = 1;
    size_t inputByteSize, outputByteSize;
    if constexpr (scenarioNum == 1) {
        inputByteSize = 256 * sizeof(half);
        outputByteSize = 16 * sizeof(half);
    } 
    else if constexpr (scenarioNum == 2) {
        inputByteSize = 512 * sizeof(half);
        outputByteSize = 32 * sizeof(half);
    } else {
        inputByteSize = 128 * sizeof(float);
        outputByteSize = 16 * sizeof(float);
    }

    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);
    aclrtStream stream = nullptr;
    aclrtCreateStream(&stream);

    uint8_t *xHost, *yHost;
    uint8_t *xDevice, *yDevice;

    aclrtMallocHost((void **)(&xHost), inputByteSize);
    aclrtMallocHost((void **)(&yHost), outputByteSize);
    aclrtMalloc((void **)&xDevice, inputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&yDevice, outputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);

