    auto O = weight.size(0);
    auto H = x.size(2);
    auto W = x.size(3);
    at::Tensor y = at::empty({N, O, H, W}, x.options());

    EXEC_NPU_CMD(aclnnConvPointwise2dCustom, x, weight, y);
    return y;
